import sys

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    t=int(data[0])
    out=[]
    for i in range(1,t+1):
        temp=int(data[i])
        out.append('HOT' if temp>900900000 else 'COLD')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

